class Queue:
 def __init__(self):
 self.queue = []

 def push(self, item):
 self.queue.append(item)

 def pop(self):
 return self.queue.pop(0)

 def peek(self):
 return self.queue[0]

# Usage example
q = Queue()
q.push(1)
q.push(2)
q.push(3)

print(q.pop()) # 1 
print(q.peek()) # 2

def palindromic_substring(s):
  all_palindromes = []

  #  check for substrings of length 3
  for i in range(len(s) - 2):
    if s[i] == s[i + 2]:
      all_palindromes.append(s[i:i + 3])

  #  check for substrings of length 4
  for i in range(len(s) - 3):
    if s[i] == s[i + 3]:
      all_palindromes.append(s[i:i + 4])

  return all_palindromes

result = palindromic_substring("abc")
print(result)

def Fibonacci(n): 
    if n<0: 
        print("Incorrect input")
    elif n==1: 
        return 0
    elif n==2: 
        return 1
    else:
        return Fibonacci(n-1)+Fibonacci(n-2) 

# Driver Program 
print(Fibonacci(n))

def odd_even(numbers):
    odd = []
    even = []
    for num in numbers:
        if num % 2 == 0:
            even.append(num)
        else:
            odd.append(num)
    return odd, even

odds, evens = odd_even([3, 4, 7, 12, 19])
print(odds) # prints: [3, 7, 19]
print(evens) # prints: [4, 12]

